def count_chinese_characters(text):
    """统计文本中汉字的个数"""
    # CJK统一表意文字范围（基本区+扩展A区，覆盖绝大多数常用汉字）
    count = 0
    for char in text:
        # 检查字符是否在CJK统一表意文字范围内
        if '\u4e00' <= char <= '\u9fff' or '\u3400' <= char <= '\u4dbf':
            count += 1
    return count

